import logging
from flask import Flask, jsonify, request

app = Flask(__name__)

# Configure logging module to include request headers, body data, and user information
logging.basicConfig(level=logging.DEBUG)
logger = logging.getLogger('api_logs')

@app.route('/', methods=['GET'])
def home():
    logger.info("Home page requested")
    return "Hello, world!"

@app.route('/user/<username>', methods=['GET'])
def get_user(username):
    logger.info(f"User {username} requested")
    # Return user data
    return jsonify({'name': 'John Doe', 'age': 30})

@app.route('/login', methods=['POST'])
def login():
    # Get authentication token and password from request body
    token = request.form['token']
    password = request.form['password']
    
    # Log request headers, body data, and user information for debugging purposes
    logger.info(f"Login attempt with token {token} and password {password}")
    return jsonify({'message': 'Login successful!'})

if __name__ == '__main__':
    app.run()